import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { db } from '../firebase';
import { doc, getDoc, collection, getDocs, updateDoc } from 'firebase/firestore';

function TeamLineup() {
  const { teamId } = useParams();
  const navigate = useNavigate();

  const [teamData, setTeamData] = useState(null);
  const [players, setPlayers] = useState([]);
  const [lineup, setLineup] = useState([]);
  const [selectedSlotIndex, setSelectedSlotIndex] = useState(null);
  const [showPlayerSelection, setShowPlayerSelection] = useState(false);
  const [pinVerified, setPinVerified] = useState(false);

  // ✅ Fetch team and player data
  useEffect(() => {
    const fetchData = async () => {
      try {
        const teamRef = doc(db, 'teams', teamId);
        const teamSnap = await getDoc(teamRef);

        if (!teamSnap.exists()) {
          alert('Team not found');
          navigate('/teams-management');
          return;
        }

        const team = teamSnap.data();
        setTeamData(team);

        const savedLineup = team.players || [];
        const filledLineup = [...savedLineup, ...Array(team.playerCount - savedLineup.length).fill(null)];
        setLineup(filledLineup);

        const playersSnap = await getDocs(collection(db, 'players'));
        const playersData = playersSnap.docs.map(doc => ({
          id: doc.id,
          ...doc.data(),
        }));
        setPlayers(playersData);

      } catch (error) {
        console.error('Error fetching data:', error);
        alert('Failed to load data.');
        navigate('/teams-management');
      }
    };

    fetchData();
  }, [teamId, navigate]);

  // ✅ PIN Verification
  useEffect(() => {
    if (teamData && !pinVerified) {
      const userPin = prompt("Enter PIN to access the lineup:");
      if (userPin === teamData.pin) {
        setPinVerified(true);
      } else {
        alert("Incorrect PIN. Access denied.");
        navigate('/teams-management');
      }
    }
  }, [teamData, pinVerified, navigate]);

  // ✅ Open player selection overlay
  const handleSelectPlayer = (index) => {
    setSelectedSlotIndex(index);
    setShowPlayerSelection(true);
  };

  // ✅ Assign player to slot
  const assignPlayerToSlot = (player) => {
    const updatedLineup = [...lineup];
    updatedLineup[selectedSlotIndex] = player;
    setLineup(updatedLineup);
    setShowPlayerSelection(false);
  };

  // ✅ Save lineup to Firestore
  const handleSaveLineup = async () => {
    try {
      const selectedPlayers = lineup.map(player => (player ? player.id : null));

      const teamRef = doc(db, 'teams', teamId);
      await updateDoc(teamRef, {
        players: selectedPlayers,
      });

      alert('Lineup saved successfully!');
    } catch (error) {
      console.error('Error saving lineup:', error);
      alert('Failed to save lineup.');
    }
  };

  if (!teamData || !pinVerified) {
    return <p>Loading...</p>;
  }

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>{teamData.name} - Lineup</h1>

      <img
        src={`${process.env.PUBLIC_URL}/images/Tactics/${teamData.playerCount}_players_${teamData.tactic}.png`}
        alt="Tactic"
        style={styles.tacticImage}
      />

      {/* ✅ Display all slots */}
      <div style={styles.lineupContainer}>
        {lineup.map((player, index) => (
          <div
            key={index}
            style={styles.slot}
            onClick={() => handleSelectPlayer(index)}
          >
            {player ? (
              <>
                <img
                  src={player.profilePicture || `${process.env.PUBLIC_URL}/images/default_profile_picture.png`}
                  alt="Player"
                  style={styles.playerImage}
                />
                <p style={styles.playerName}>{player.lastName}, {player.firstName}</p>
                <p style={styles.playerPosition}>{player.favoritePosition}</p>
                <p style={styles.playerPower}>Power: {player.powerRating}</p>
              </>
            ) : (
              <p style={styles.emptySlot}>+ Slot {index + 1}</p>
            )}
          </div>
        ))}
      </div>

      {/* ✅ Player selection overlay */}
{showPlayerSelection && (
  <div style={styles.overlay}>
    <div style={styles.playerSelectionContainer}>
      <h2 style={styles.selectTitle}>Select a Player</h2>

      <div style={styles.playerGrid}>
        {players.map((player) => (
          <div
            key={player.id}
            style={styles.playerCard}
            onClick={() => assignPlayerToSlot(player)}
          >
            <img
              src={player.profilePicture || `${process.env.PUBLIC_URL}/images/default_profile_picture.png`}
              alt="Player"
              style={styles.playerCardImage}
            />
            <div style={styles.playerInfo}>
              <p style={styles.playerName}>{player.lastName}, {player.firstName}</p>
              <p style={styles.playerPosition}>{player.favoritePosition}</p>
              <p style={styles.playerPower}>Power: {player.powerRating}</p>
            </div>
          </div>
        ))}
      </div>

      <button style={styles.cancelButton} onClick={() => setShowPlayerSelection(false)}>
        ✖ Cancel
      </button>
    </div>
  </div>
)}

      <button style={styles.saveButton} onClick={handleSaveLineup}>
        Save Lineup
      </button>

      <button style={styles.backButton} onClick={() => navigate('/teams-management')}>
        Back to Teams Management
      </button>
    </div>
  );
}

const styles = {
  container: {
    backgroundColor: '#D6F8D6',
    minHeight: '100vh',
    padding: '20px',
    fontFamily: "'Press Start 2P', cursive",  // Old-school font
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
  },
  title: {
    fontSize: '24px',
    marginBottom: '20px',
    color: '#293F14',
    textShadow: '2px 2px #7FC6A4',  // Retro shadow effect
  },
  tacticImage: {
    width: '50%',
    height: 'auto',
    marginBottom: '30px',
    borderRadius: '10px',
    border: '2px solid #386C0B',
  },
  lineupContainer: {
    display: 'flex',
    gap: '20px',
    flexWrap: 'wrap',
    justifyContent: 'center',
  },
  slot: {
    width: '120px',
    height: '160px',
    backgroundColor: '#7FC6A4',
    borderRadius: '10px',
    cursor: 'pointer',
    textAlign: 'center',
    border: '2px solid #5D737E',
    boxShadow: '3px 3px #386C0B',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
    alignItems: 'center',
  },
  playerImage: {
    width: '100%',
    height: '100%',
    objectFit: 'cover',
    borderRadius: '8px',
    border: '2px solid #293F14',
  },
  overlay: {
    position: 'fixed',
    top: 0,
    left: 0,
    width: '100vw',
    height: '100vh',
    backgroundColor: 'rgba(0, 0, 0, 0.85)',  // Darker overlay for retro look
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    zIndex: 1000,
  },
  playerSelectionContainer: {
    backgroundColor: '#D6F8D6',
    padding: '30px',
    borderRadius: '10px',
    boxShadow: '0 0 20px rgba(0, 0, 0, 0.5)',
    textAlign: 'center',
    width: '80%',
    maxHeight: '80vh',
    overflowY: 'auto',
    border: '3px solid #293F14',
  },
  playerGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fit, minmax(120px, 1fr))',
    gap: '20px',
  },
  playerCard: {
    width: '120px',
    height: '200px',
    backgroundColor: '#7FC6A4',
    color: '#293F14',
    borderRadius: '10px',
    textAlign: 'center',
    padding: '10px',
    cursor: 'pointer',
    transition: 'transform 0.2s, box-shadow 0.2s',
    boxShadow: '2px 2px 8px rgba(0, 0, 0, 0.3)',
  },
  playerCardImage: {
    width: '100%',
    height: '120px',
    objectFit: 'cover',
    borderRadius: '8px',
    border: '2px solid #5D737E',
  },
  playerInfo: {
    marginTop: '8px',
    fontSize: '10px',
  },
  playerName: {
    fontWeight: 'bold',
    fontSize: '12px',
  },
  playerPosition: {
    fontSize: '10px',
    color: '#386C0B',
  },
  playerPower: {
    fontSize: '10px',
    color: '#5D737E',
  },
  saveButton: {
    backgroundColor: '#386C0B',
    padding: '10px 20px',
    color: '#FFF',
    marginTop: '20px',
    fontFamily: "'Press Start 2P', cursive",
    borderRadius: '8px',
    border: '2px solid #293F14',
    cursor: 'pointer',
  },
  cancelButton: {
    marginTop: '20px',
    backgroundColor: '#C0392B',
    color: '#FFFFFF',
    padding: '10px 20px',
    borderRadius: '8px',
    fontFamily: "'Press Start 2P', cursive",
    border: '2px solid #293F14',
    cursor: 'pointer',
    transition: 'background-color 0.3s',
  },
  backButton: {
    marginTop: '10px',
    backgroundColor: '#5D737E',
    color: '#FFFFFF',
    padding: '10px 20px',
    borderRadius: '8px',
    fontFamily: "'Press Start 2P', cursive",
    border: '2px solid #293F14',
    cursor: 'pointer',
  },
};

export default TeamLineup;
